      'ssh-key-generator': { name: 'SSH 키 생성기', desc: 'RSA, ECDSA SSH 키를 만들어 줍니다.', ui: {"button0":"복사","button1":"다운로드","label2":"키 유형","label3":"RSA 키 크기","label4":"코멘트 (선택)","placeholder5":"user@host 또는 설명","option6":"2048비트 (최소, 빠름)","option7":"3072비트 (균형)","option8":"4096비트 (최대 보안, 느림)","stat9":"🔓 공개 키","stat10":"🔐 개인 키","heading11":"100% 클라이언트 측 & 비공개","heading12":"지문 (SHA-256)","desc13":"식별을 위해 공개 키에 추가됨","desc14":"원격 서버의 ~/.ssh/authorized_keys에 추가하세요","desc15":"⚠️ 비공개로 유지하세요! 권한 600으로 저장.","desc16":"로컬 머신:","desc17":"원격 서버:","badge18":"비공개 & 보안","badge19":"내 브라우저에서만","badge20":"개인정보 보호"}, js: {"text0":"✓ 복사됨","text1":"복사","tpl2":"mkdir -p ~/.ssh && chmod 700 ~/.ssh\necho \\\"PUBLIC_KEY\\\" >> ~/.ssh/authorized_keys\nchmod 600 ~/.ssh/authorized_keys"} },
